// Rename PDF using report_name from previous node if available

for (const item of items) {
  const base = item.json?.report_name || "SmartInfra_VA_Report_L1";
  const filename = `${base}.pdf`;

  const bin = item.binary || {};
  const key = bin.pdf ? "pdf" : (bin.data ? "data" : Object.keys(bin)[0]);

  if (!key || !bin[key]) {
    item.json = { ...(item.json || {}), error: "No binary file found to rename" };
    continue;
  }

  bin[key].fileName = filename;
  bin[key].mimeType = "application/pdf";
  bin[key].fileExtension = "pdf";

  item.binary = bin;
  item.json = { ...(item.json || {}), pdf_filename: filename, pdf_binary_key: key };
}

return items;

return items.map(item => {
  const uploadJson = $node["Google Drive (Upload)"].json;
  const fileId = uploadJson?.id;

  const driveLink = fileId
    ? `https://drive.google.com/file/d/${fileId}/view?usp=sharing`
    : '';

  return {
    json: {
      ...item.json,
      drive_file_id: fileId,
      drive_link: driveLink,
    },
    binary: item.binary,
  };
});

const d = $json || {};

// ----------------------------
// Helpers
// ----------------------------
function num(v, def = 0) {
  const n = Number(v);
  return Number.isFinite(n) ? n : def;
}

function text(v, def = "-") {
  const s = String(v ?? "").trim();
  return s ? s : def;
}

function upper(v, def = "") {
  const s = String(v ?? def).trim();
  return s ? s.toUpperCase() : def;
}

// ----------------------------
// Main values
// ----------------------------
const run_id = text(d.run_id, "-");
const scan_time_th = text(d.scan_time_th, "-");

const total_hosts = num(d.total_hosts);
const total_findings = num(d.total_findings);

const critical = num(d.critical_count);
const high = num(d.high_count);
const medium = num(d.medium_count);
const low = num(d.low_count);

const security_status = text(d.security_status, "NORMAL");
const security_score = num(d.security_score);
const security_grade = text(d.security_grade, "-");
const threat_level = text(d.threat_level, "LOW");

const pdf_link = text(d.pdf_link || d.drive_link || d.webViewLink, "");

// ----------------------------
// Risk Index
// ใช้ค่าที่มีอยู่ก่อน แต่ถ้าเป็น 0 แบบไม่สมเหตุผล
// ให้คำนวณใหม่อัตโนมัติ
// ----------------------------
let risk_index = num(d.risk_index, -1);

const calculated_risk_index =
  (critical * 10) +
  (high * 5) +
  (medium * 2) +
  (low * 1);

if (
  risk_index < 0 ||
  (!critical && !high && !medium && !low ? false : risk_index === 0)
) {
  risk_index = calculated_risk_index;
}

// ----------------------------
// Vulnerability Summary
// ----------------------------
const cve_detected = num(
  d.cve_detected ??
  d.cve_count ??
  d.total_cve ??
  d.cve_total ??
  0
);

const kev_detected = num(
  d.kev_detected ??
  d.kev_count ??
  d.total_kev ??
  d.kev_total ??
  0
);

// ----------------------------
// Alert decision
// ----------------------------
const has_high_or_critical = (critical + high) > 0;

// ----------------------------
// Header / Headline
// ----------------------------
let header = "";
let headline = "";

if (critical > 0) {
  header = "🚨 SmartInfra Security Alert";
  headline = "พบความเสี่ยงระดับ CRITICAL ในระบบ";
} else if (high > 0) {
  header = "⚠️ SmartInfra Security Alert";
  headline = "พบความเสี่ยงระดับ HIGH ในระบบ";
} else if (medium > 0) {
  header = "🟡 SmartInfra Security Summary";
  headline = "พบความเสี่ยงระดับ MEDIUM ควรติดตาม";
} else {
  header = "🛡 SmartInfra Security Summary";
  headline = "ไม่พบความเสี่ยงระดับสูงหรือวิกฤต";
}

// ----------------------------
// Top Risk Host
// priority:
// 1) existing top_risk_* fields
// 2) auto-detect from risk_findings
// ----------------------------
let top_risk_host = text(
  d.top_risk_host ??
  d.top_host ??
  d.most_risky_host,
  "-"
);

let top_risk_service = text(
  d.top_risk_service ??
  d.top_service ??
  d.most_risky_service,
  "-"
);

let top_risk_cve = text(
  d.top_risk_cve ??
  d.top_cve ??
  d.most_risky_cve,
  "-"
);

if (
  top_risk_host === "-" &&
  Array.isArray(d.risk_findings) &&
  d.risk_findings.length > 0
) {
  const scored = [...d.risk_findings].map((r) => {
    const score =
      num(r.risk_score, -1) >= 0
        ? num(r.risk_score)
        : (
            upper(r.risk_level) === "CRITICAL" ? 100 :
            upper(r.risk_level) === "HIGH" ? 80 :
            upper(r.risk_level) === "MEDIUM" ? 50 :
            upper(r.risk_level) === "LOW" ? 20 : 0
          );

    const host = text(r.host, "-");
    const service = text(r.service, "");
    const port = text(r.port, "");

    let serviceText = "-";
    if (service && service !== "-" && port && port !== "-") serviceText = `${service} Port ${port}`;
    else if (service && service !== "-") serviceText = service;
    else if (port && port !== "-") serviceText = `Port ${port}`;

    let cveText = "-";
    if (text(r.cve, "") && text(r.cve, "") !== "-") {
      cveText = text(r.cve, "-");
    } else if (Array.isArray(r.cves) && r.cves.length > 0) {
      cveText = text(r.cves[0], "-");
    }

    return {
      host,
      serviceText,
      cveText,
      score
    };
  });

  scored.sort((a, b) => b.score - a.score);

  const top = scored[0];
  if (top) {
    top_risk_host = top.host || "-";
    top_risk_service = top.serviceText || "-";
    top_risk_cve = top.cveText || "-";
  }
}

// ----------------------------
// Top Exposed Services
// ----------------------------
let top_services_block = "";

if (Array.isArray(d.risk_findings) && d.risk_findings.length > 0) {
  const counter = {};

  for (const r of d.risk_findings) {
    const svc = text(r.service, "");
    const port = text(r.port, "");
    let key = "";

    if (svc && svc !== "-" && port && port !== "-") key = `${svc} Port ${port}`;
    else if (svc && svc !== "-") key = svc;
    else if (port && port !== "-") key = `Port ${port}`;

    if (!key) continue;
    counter[key] = (counter[key] || 0) + 1;
  }

  const topServices = Object.entries(counter)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 3);

  if (topServices.length > 0) {
    top_services_block += `🔥 Top Exposed Services\n`;
    for (const [name, count] of topServices) {
      top_services_block += `- ${name} (${count})\n`;
    }
    top_services_block += `\n`;
  }
}

// ----------------------------
// Recommendations
// ----------------------------
let recommendationLines = [];

if (critical > 0) {
  recommendationLines = [
    "เร่งตรวจสอบ host และ service ที่มีความเสี่ยงสูงสุด",
    "อัปเดต patch และ remediation ที่เกี่ยวข้องทันที",
    "จำกัดการเข้าถึง service ที่เปิดเผยสู่เครือข่าย",
    "ตรวจสอบ firewall / ACL / segmentation เพิ่มเติม"
  ];
} else if (high > 0) {
  recommendationLines = [
    "ตรวจสอบ service ที่เปิดใช้งานและ port ที่ไม่จำเป็น",
    "อัปเดต patch และช่องโหว่ที่เกี่ยวข้อง",
    "ทบทวน firewall policy และการควบคุมการเข้าถึง",
    "ติดตาม host ที่มีความเสี่ยงสูงเป็นพิเศษ"
  ];
} else if (medium > 0) {
  recommendationLines = [
    "ตรวจสอบรายการความเสี่ยงและวางแผน remediation",
    "ทบทวน configuration ที่เปิดเผยเกินความจำเป็น",
    "เฝ้าระวัง host ที่มีแนวโน้มความเสี่ยงเพิ่มขึ้น"
  ];
} else {
  recommendationLines = [
    "ติดตามผลการสแกนอย่างต่อเนื่อง",
    "ทบทวน asset และ service inventory เป็นระยะ",
    "รักษาระดับ patching และ hardening policy อย่างสม่ำเสมอ"
  ];
}

// ----------------------------
// Build message
// ----------------------------
let msg = "";

msg += `${header}\n`;
msg += `🕒 ${scan_time_th}\n`;
msg += `🆔 Run ID: ${run_id}\n\n`;

msg += `📌 สถานะ: ${security_status}\n`;
msg += `🔥 Threat Level: ${threat_level}\n`;
msg += `🏅 Security Grade: ${security_grade}\n`;
msg += `📊 Security Score: ${security_score}\n`;
msg += `📉 Risk Index: ${risk_index}\n\n`;

msg += `🖥 Total Hosts: ${total_hosts}\n`;
msg += `📍 Total Findings: ${total_findings}\n\n`;

msg += `📈 Risk Distribution\n`;
msg += `🟥 CRITICAL: ${critical}\n`;
msg += `🟧 HIGH: ${high}\n`;
msg += `🟨 MEDIUM: ${medium}\n`;
msg += `🟩 LOW: ${low}\n\n`;

msg += `🧬 Vulnerability Summary\n`;
msg += `CVE Detected: ${cve_detected}\n`;
msg += `KEV Detected: ${kev_detected}\n\n`;

msg += `📝 ${headline}\n\n`;

if (top_risk_host !== "-") {
  msg += `⚠️ Top Risk Host\n`;
  msg += `🖥 ${top_risk_host}\n`;

  if (top_risk_service !== "-") {
    msg += `🔌 ${top_risk_service}\n`;
  }

  if (top_risk_cve !== "-") {
    msg += `🧬 ${top_risk_cve}\n`;
  }

  msg += `\n`;
}

if (top_services_block) {
  msg += top_services_block;
}

msg += `🔧 Recommendation\n`;
for (const line of recommendationLines) {
  msg += `- ${line}\n`;
}

if (pdf_link) {
  msg += `\n📄 Report (PDF):\n${pdf_link}`;
}

// ----------------------------
// Output
// ----------------------------
return {
  json: {
    ...d,
    risk_index,
    line_message: msg,
    line_header: header,
    line_headline: headline,
    has_high_or_critical,
    cve_detected,
    kev_detected,
    top_risk_host,
    top_risk_service,
    top_risk_cve,
    line_recommendations: recommendationLines
  }
};

const current = $json || {};

// --------------------------------------------------
// Helper
// --------------------------------------------------
function toNumber(v, def = 0) {
  const n = Number(v);
  return Number.isFinite(n) ? n : def;
}

function pad2(n) {
  return String(n).padStart(2, "0");
}

function tryNodeJson(nodeName) {
  try {
    return $(nodeName).all()[0]?.json || {};
  } catch (e) {
    return {};
  }
}

// --------------------------------------------------
// Try to get report summary from possible upstream nodes
// --------------------------------------------------
let report = {};

// ลองดึงจาก node ที่น่าจะมี summary ก่อน
const candidates = [
  "CODE | Build Report Sections",
  "CODE | Build HTML Template",
  "CODE | Prepare Report Data"
];

for (const name of candidates) {
  const data = tryNodeJson(name);
  if (data && Object.keys(data).length > 0) {
    report = data;
    break;
  }
}

// fallback สุดท้าย ใช้ current ถ้าไม่มี node summary
if (!report || Object.keys(report).length === 0) {
  report = { ...current };
}

// --------------------------------------------------
// Extract summary values
// --------------------------------------------------
const critical = toNumber(
  current.critical_count ??
  report.critical_count ??
  report.risk_distribution?.CRITICAL ??
  0
);

const high = toNumber(
  current.high_count ??
  report.high_count ??
  report.risk_distribution?.HIGH ??
  0
);

const medium = toNumber(
  current.medium_count ??
  report.medium_count ??
  report.risk_distribution?.MEDIUM ??
  0
);

const low = toNumber(
  current.low_count ??
  report.low_count ??
  report.risk_distribution?.LOW ??
  0
);

const total_hosts = toNumber(current.total_hosts ?? report.total_hosts ?? 0);
const total_findings = toNumber(current.total_findings ?? report.total_findings ?? 0);

const scan_time_th =
  current.scan_time_th ||
  report.scan_time_th ||
  "";

const report_name =
  current.report_name ||
  report.report_name ||
  "SmartInfra_Security_Report";

const avg_risk_score = toNumber(
  current.avg_risk_score ??
  report.avg_risk_score ??
  0
);

const avg_security_score = toNumber(
  current.avg_security_score ??
  report.avg_security_score ??
  Math.max(0, 100 - avg_risk_score)
);

const security_grade =
  current.security_grade ||
  report.security_grade ||
  "-";

const kev_count = toNumber(
  current.kev_count ??
  report.kev_count ??
  0
);

const cve_count = toNumber(
  current.cve_count ??
  report.cve_count ??
  0
);

const overall_threat =
  String(current.overall_threat || report.overall_threat || "").toUpperCase() ||
  (critical > 0 ? "CRITICAL" :
   high > 0 ? "HIGH" :
   medium > 0 ? "MEDIUM" :
   low > 0 ? "LOW" : "NORMAL");

// --------------------------------------------------
// Build run_id
// --------------------------------------------------
const now = new Date();
const yyyy = now.getFullYear();
const mm = pad2(now.getMonth() + 1);
const dd = pad2(now.getDate());
const hh = pad2(now.getHours());
const mi = pad2(now.getMinutes());
const ss = pad2(now.getSeconds());

const run_id =
  current.run_id ||
  report.run_id ||
  `RUN-${yyyy}${mm}${dd}-${hh}${mi}${ss}`;

// --------------------------------------------------
// Executive security status
// --------------------------------------------------
let security_status = "NORMAL";
if (critical > 0) security_status = "EMERGENCY";
else if (high > 0) security_status = "ATTENTION";
else if (medium > 0) security_status = "REVIEW";

// --------------------------------------------------
// Email decision
// --------------------------------------------------
let email_subject = "";
let alert_level_label = "";
let email_intro = "";
let email_priority = "normal";

if (critical > 0) {
  email_subject = `🚨 [CRITICAL] SmartInfra Security Alert | ${scan_time_th || "-"}`;
  alert_level_label = "CRITICAL";
  email_intro = "พบความเสี่ยงระดับวิกฤตในผลการสแกนล่าสุด ควรตรวจสอบและดำเนินการโดยเร่งด่วน";
  email_priority = "high";
} else if (high > 0) {
  email_subject = `⚠️ [HIGH] SmartInfra Risk Report | ${scan_time_th || "-"}`;
  alert_level_label = "HIGH";
  email_intro = "พบความเสี่ยงระดับสูงในผลการสแกนล่าสุด ควรวางแผนตรวจสอบและแก้ไขโดยเร็ว";
  email_priority = "high";
} else if (medium > 0) {
  email_subject = `🟡 [MEDIUM] SmartInfra Security Summary | ${scan_time_th || "-"}`;
  alert_level_label = "MEDIUM";
  email_intro = "พบความเสี่ยงระดับปานกลางในผลการสแกนล่าสุด ควรตรวจสอบและวางแผนปรับปรุง";
  email_priority = "normal";
} else {
  email_subject = `🛡 [NORMAL] SmartInfra Daily Security Summary | ${scan_time_th || "-"}`;
  alert_level_label = "NORMAL";
  email_intro = "ไม่พบความเสี่ยงระดับสูงหรือวิกฤตในรอบการสแกนนี้ ระบบอยู่ในสถานะปกติ";
  email_priority = "normal";
}

// --------------------------------------------------
// PDF link / drive link
// --------------------------------------------------
const drive_link =
  current.drive_link ||
  current.webViewLink ||
  report.drive_link ||
  report.webViewLink ||
  (current.id ? `https://drive.google.com/file/d/${current.id}/view?usp=sharing` : "") ||
  "";

// --------------------------------------------------
// HTML email
// --------------------------------------------------
const email_html = `
<div style="font-family:Arial,Helvetica,sans-serif;color:#1f2937;line-height:1.6;max-width:820px;">
  <h2 style="margin:0 0 12px 0;color:#123B64;">SmartInfra Security Scan Report</h2>

  <table style="border-collapse:collapse;width:100%;max-width:620px;font-size:14px;">
    <tr><td style="padding:4px 0;width:180px;"><b>Run ID:</b></td><td style="padding:4px 0;">${run_id}</td></tr>
    <tr><td style="padding:4px 0;"><b>Security Status:</b></td><td style="padding:4px 0;">${security_status}</td></tr>
    <tr><td style="padding:4px 0;"><b>Alert Level:</b></td><td style="padding:4px 0;">${alert_level_label}</td></tr>
    <tr><td style="padding:4px 0;"><b>Scan Time:</b></td><td style="padding:4px 0;">${scan_time_th || "-"}</td></tr>
    <tr><td style="padding:4px 0;"><b>Total Hosts:</b></td><td style="padding:4px 0;">${total_hosts}</td></tr>
    <tr><td style="padding:4px 0;"><b>Total Findings:</b></td><td style="padding:4px 0;">${total_findings}</td></tr>
    <tr><td style="padding:4px 0;"><b>Average Risk Score:</b></td><td style="padding:4px 0;">${avg_risk_score.toFixed(1)}</td></tr>
    <tr><td style="padding:4px 0;"><b>Average Security Score:</b></td><td style="padding:4px 0;">${avg_security_score.toFixed(1)}</td></tr>
    <tr><td style="padding:4px 0;"><b>Security Grade:</b></td><td style="padding:4px 0;">${security_grade}</td></tr>
  </table>

  <p style="margin:16px 0 10px 0;">${email_intro}</p>

  <div style="margin:14px 0;padding:14px 16px;background:#f8fafc;border:1px solid #dbe4ee;border-radius:10px;max-width:620px;">
    <div style="font-weight:bold;color:#123B64;margin-bottom:8px;">Risk Distribution</div>
    <ul style="margin:0;padding-left:20px;">
      <li><b>CRITICAL:</b> ${critical}</li>
      <li><b>HIGH:</b> ${high}</li>
      <li><b>MEDIUM:</b> ${medium}</li>
      <li><b>LOW:</b> ${low}</li>
      <li><b>CVE Detected:</b> ${cve_count}</li>
      <li><b>KEV Detected:</b> ${kev_count}</li>
    </ul>
  </div>

  ${
    drive_link
      ? `<p style="margin:14px 0 0 0;"><b>Download Report (PDF):</b></p>
         <p style="margin:4px 0 16px 0;">
           <a href="${drive_link}" target="_blank" style="color:#1d4ed8;text-decoration:underline;">
             Open Vulnerability Assessment Report
           </a>
         </p>`
      : ``
  }

  <hr style="border:none;border-top:1px solid #d1d5db;margin:18px 0;" />

  <p style="font-size:12px;color:#6b7280;margin:0 0 8px 0;">
    This is an automated security report generated by SmartInfra Security Suite.
    Please review the full PDF report for full findings and remediation recommendations.
  </p>

  <p style="font-size:12px;color:#6b7280;margin:0;">
    ---<br/>
    This email was sent automatically with <b>n8n</b>
  </p>
</div>
`;

// --------------------------------------------------
// Plain text
// --------------------------------------------------
const email_text = `
SmartInfra Security Scan Report

Run ID: ${run_id}
Security Status: ${security_status}
Alert Level: ${alert_level_label}
Scan Time: ${scan_time_th || "-"}
Total Hosts: ${total_hosts}
Total Findings: ${total_findings}
Average Risk Score: ${avg_risk_score.toFixed(1)}
Average Security Score: ${avg_security_score.toFixed(1)}
Security Grade: ${security_grade}

Risk Distribution
- CRITICAL: ${critical}
- HIGH: ${high}
- MEDIUM: ${medium}
- LOW: ${low}
- CVE Detected: ${cve_count}
- KEV Detected: ${kev_count}

${drive_link ? `Download Report (PDF): ${drive_link}` : ""}

This is an automated security report generated by SmartInfra Security Suite.
`;

// --------------------------------------------------
// Output
// --------------------------------------------------
return {
  json: {
    ...current,
    ...report,

    run_id,
    report_name,
    scan_time_th,
    total_hosts,
    total_findings,
    avg_risk_score,
    avg_security_score,
    security_grade,
    overall_threat,

    critical_count: critical,
    high_count: high,
    medium_count: medium,
    low_count: low,
    cve_count,
    kev_count,

    security_status,
    alert_level_label,
    email_subject,
    email_intro,
    email_priority,
    email_html,
    email_text,
    drive_link
  },
  binary: $binary
};

const d = $json || {};

// ------------------
// Helper
// ------------------
function num(v, def = 0) {
  const n = Number(v);
  return Number.isFinite(n) ? n : def;
}

function text(v, def = "-") {
  const s = String(v ?? "").trim();
  return s ? s : def;
}

function gradeFromScore(score) {
  if (score >= 90) return "A";
  if (score >= 80) return "B";
  if (score >= 70) return "C";
  if (score >= 60) return "D";
  return "F";
}

// ------------------
// Extract counts
// ------------------
const critical = num(d.critical_count);
const high = num(d.high_count);
const medium = num(d.medium_count);
const low = num(d.low_count);

const total_hosts = num(d.total_hosts);
const total_findings = num(d.total_findings);
const avg_risk_score = num(d.avg_risk_score);

// ------------------
// Security Score
// ใช้ค่าที่มีอยู่ก่อน ถ้าไม่มีค่อยคำนวณ
// ------------------
let security_score;

if (d.security_score !== undefined && d.security_score !== null && d.security_score !== "") {
  security_score = num(d.security_score);
} else if (d.avg_security_score !== undefined && d.avg_security_score !== null && d.avg_security_score !== "") {
  security_score = num(d.avg_security_score);
} else {
  security_score = 100 - avg_risk_score;
}

if (security_score < 0) security_score = 0;
security_score = Number(security_score.toFixed(1));

// ------------------
// Security Status
// ------------------
let security_status = text(d.security_status, "");

if (!security_status || security_status === "-") {
  if (critical > 0) security_status = "EMERGENCY";
  else if (high > 0) security_status = "ATTENTION";
  else if (medium > 0) security_status = "REVIEW";
  else security_status = "NORMAL";
}

// ------------------
// Security Grade
// ------------------
let security_grade = text(d.security_grade, "");

if (!security_grade || security_grade === "-") {
  security_grade = gradeFromScore(security_score);
}

// ------------------
// Threat Level
// ------------------
let threat_level = text(d.threat_level, "");

if (!threat_level || threat_level === "-") {
  if (critical > 0) threat_level = "SEVERE";
  else if (high > 0) threat_level = "HIGH";
  else if (medium > 0) threat_level = "MODERATE";
  else threat_level = "LOW";
}

// ------------------
// Risk Index
// ใช้ค่าที่มีอยู่ก่อน ถ้าไม่มีค่อยคำนวณ
// ------------------
let risk_index;

if (d.risk_index !== undefined && d.risk_index !== null && d.risk_index !== "") {
  risk_index = num(d.risk_index);
} else {
  risk_index =
    (critical * 10) +
    (high * 5) +
    (medium * 2) +
    (low * 1);
}

// ------------------
// CVE / KEV Summary
// ------------------
const cve_detected = num(
  d.cve_detected ??
  d.cve_count ??
  d.total_cve ??
  d.cve_total ??
  0
);

const kev_detected = num(
  d.kev_detected ??
  d.kev_count ??
  d.total_kev ??
  d.kev_total ??
  0
);

// ------------------
// Top Risk Host
// ------------------
const top_risk_host = text(
  d.top_risk_host ??
  d.top_host ??
  d.most_risky_host,
  "-"
);

const top_risk_service = text(
  d.top_risk_service ??
  d.top_service ??
  d.most_risky_service,
  "-"
);

const top_risk_cve = text(
  d.top_risk_cve ??
  d.top_cve ??
  d.most_risky_cve,
  "-"
);

// ------------------
// Links / meta
// ------------------
const run_id = text(d.run_id, "-");
const report_name = text(d.report_name, "SmartInfra_Security_Report");
const scan_time_th = text(d.scan_time_th, "-");

const pdf_link = text(
  d.pdf_link ??
  d.drive_link ??
  d.webViewLink,
  ""
);

// ------------------
// LINE / Email status
// ใช้ค่าที่มีอยู่ก่อน ถ้าไม่มีค่อย default
// ------------------
const line_channel = text(d.line_channel, "ALERT");
const line_status = text(d.line_status, "SENT");
const email_status = text(d.email_status, "SENT");

// ------------------
// Output
// ------------------
return {
  json: {
    ...d,

    run_id,
    report_name,
    scan_time_th,

    total_hosts,
    total_findings,

    critical_count: critical,
    high_count: high,
    medium_count: medium,
    low_count: low,

    avg_risk_score,
    security_status,
    security_score,
    security_grade,
    threat_level,
    risk_index,

    pdf_link,

    cve_detected,
    kev_detected,

    top_risk_host,
    top_risk_service,
    top_risk_cve,

    line_channel,
    line_status,
    email_status,

    created_at: new Date().toISOString()
  }
};

// CODE | Filter Latest Scan
// Mode: Run Once for All Items

function minuteKey(v) {
  const s = String(v || '').trim();
  // เอาถึงระดับนาที เช่น 2026-03-11T21:55
  return s ? s.slice(0, 16) : '';
}

// หา minute ล่าสุด
let latestMinute = '';

for (const item of items) {
  const key = minuteKey(item.json.detected_at);
  if (key && key > latestMinute) {
    latestMinute = key;
  }
}

// คืนทุก item ที่อยู่ใน minute เดียวกัน
return items.filter(item => minuteKey(item.json.detected_at) === latestMinute);

// CODE | Build Security Metrics
// Run Once for All Items

const rows = items.map(i => i.json || {});

function toNum(v, def = 0) {
  const n = Number(v);
  return Number.isFinite(n) ? n : def;
}

function isTrueLike(v) {
  const s = String(v ?? "").trim().toLowerCase();
  return ["1", "true", "yes", "y", "on"].includes(s);
}

let critical = 0;
let high = 0;
let medium = 0;
let low = 0;
let info = 0;

let totalRiskScore = 0;
let cveCount = 0;
let kevCount = 0;

const affectedHosts = new Set();
const hostStats = {};

for (const r of rows) {
  const host = String(r.host || r.ip || r.target || "").trim();
  const level = String(r.risk_level || r.severity || "UNKNOWN").trim().toUpperCase();
  const score = toNum(r.risk_score, 0);

  if (host) {
    affectedHosts.add(host);

    if (!hostStats[host]) {
      hostStats[host] = {
        host,
        findings: 0,
        critical: 0,
        high: 0,
        medium: 0,
        low: 0,
        risk_score_sum: 0,
        kev_count: 0,
        ports: new Set(),
      };
    }

    hostStats[host].findings += 1;
    hostStats[host].risk_score_sum += score;

    if (r.port !== undefined && r.port !== null && String(r.port).trim() !== "") {
      hostStats[host].ports.add(String(r.port).trim());
    }
  }

  totalRiskScore += score;

  if (level === "CRITICAL") {
    critical++;
    if (host) hostStats[host].critical++;
  } else if (level === "HIGH") {
    high++;
    if (host) hostStats[host].high++;
  } else if (level === "MEDIUM") {
    medium++;
    if (host) hostStats[host].medium++;
  } else if (level === "LOW") {
    low++;
    if (host) hostStats[host].low++;
  } else {
    info++;
  }

  const cve = String(r.cve || "").trim();
  if (cve) cveCount++;

  const kev =
    isTrueLike(r.kev) ||
    isTrueLike(r.is_kev) ||
    isTrueLike(r.known_exploited) ||
    isTrueLike(r.cisa_kev);

  if (kev) {
    kevCount++;
    if (host) hostStats[host].kev_count++;
  }
}

const totalFindings = rows.length;
const avgRiskScore = totalFindings > 0 ? +(totalRiskScore / totalFindings).toFixed(1) : 0;

// จัดอันดับ Top Hosts
const rankedHosts = Object.values(hostStats)
  .map(h => {
    const avg = h.findings > 0 ? h.risk_score_sum / h.findings : 0;
    const priorityScore =
      (h.critical * 10) +
      (h.high * 6) +
      (h.medium * 3) +
      (h.low * 1) +
      (h.kev_count * 8) +
      h.findings;

    return {
      host: h.host,
      findings: h.findings,
      critical: h.critical,
      high: h.high,
      medium: h.medium,
      low: h.low,
      kev_count: h.kev_count,
      avg_risk_score: +avg.toFixed(1),
      ports: Array.from(h.ports).sort((a, b) => Number(a) - Number(b)).join(", "),
      priority_score: priorityScore,
      max_risk_level:
        h.critical > 0 ? "CRITICAL" :
        h.high > 0 ? "HIGH" :
        h.medium > 0 ? "MEDIUM" :
        h.low > 0 ? "LOW" : "INFO"
    };
  })
  .sort((a, b) => b.priority_score - a.priority_score);

const topAffectedHosts = rankedHosts.slice(0, 3);

// สรุปภาพรวมเบื้องต้น
let overallRiskPosture = "LOW";
if (critical > 0) overallRiskPosture = "CRITICAL";
else if (high > 0) overallRiskPosture = "HIGH";
else if (medium > 0) overallRiskPosture = "MEDIUM";

return [
  {
    json: {
      scan_time: new Date().toISOString(),
      affected_hosts: affectedHosts.size,
      total_findings: totalFindings,
      critical,
      high,
      medium,
      low,
      info,
      cve_count: cveCount,
      kev_count: kevCount,
      avg_risk_score: avgRiskScore,
      overall_risk_posture: overallRiskPosture,
      top_affected_hosts: topAffectedHosts
    }
  }
];

// CODE | Calculate Security Score
// Run Once for All Items

const d = items[0].json || {};

function toNum(v, def = 0) {
  const n = Number(v);
  return Number.isFinite(n) ? n : def;
}

const critical = toNum(d.critical);
const high = toNum(d.high);
const medium = toNum(d.medium);
const low = toNum(d.low);
const kevCount = toNum(d.kev_count);
const avgRiskScore = toNum(d.avg_risk_score);

// ---------------- threat level ----------------
let threatLevel = "LOW";
if (critical > 0) threatLevel = "CRITICAL";
else if (high > 0) threatLevel = "HIGH";
else if (medium > 0) threatLevel = "MEDIUM";
else if (low > 0) threatLevel = "LOW";
else threatLevel = "INFO";

// ---------------- risk index (numeric) ----------------
// น้ำหนัก severity แบบสมดุล
const riskIndex =
  (critical * 10) +
  (high * 6) +
  (medium * 3) +
  (low * 1) +
  (kevCount * 8);

// ---------------- security score (0..100) ----------------
// penalty มาจาก risk index + avg risk score
let securityScore = 100 - (riskIndex + (avgRiskScore * 0.5));

// clamp ให้อยู่ในช่วง 0..100
securityScore = Math.max(0, Math.min(100, securityScore));

// ปัด 1 ตำแหน่ง
securityScore = Number(securityScore.toFixed(1));

// ---------------- grade ----------------
let securityGrade = "A";
if (securityScore < 90) securityGrade = "B";
if (securityScore < 80) securityGrade = "C";
if (securityScore < 70) securityGrade = "D";
if (securityScore < 60) securityGrade = "F";

// ---------------- status / posture ----------------
let securityStatus = "NORMAL";
if (threatLevel === "CRITICAL") securityStatus = "CRITICAL";
else if (threatLevel === "HIGH") securityStatus = "ELEVATED";
else if (threatLevel === "MEDIUM") securityStatus = "WATCH";
else if (threatLevel === "LOW") securityStatus = "NORMAL";
else securityStatus = "INFO";

const overallRiskPosture = threatLevel;

// ---------------- summary text ----------------
let executiveSummary = "System posture appears stable with low immediate exposure.";
if (threatLevel === "CRITICAL") {
  executiveSummary = "Critical risk posture detected. Immediate remediation is strongly recommended.";
} else if (threatLevel === "HIGH") {
  executiveSummary = "Elevated risk posture. High-risk exposures should be prioritized for remediation.";
} else if (threatLevel === "MEDIUM") {
  executiveSummary = "Moderate exposure detected. Corrective controls and hardening are recommended.";
} else if (threatLevel === "LOW") {
  executiveSummary = "Low-risk exposures detected. Maintain patching and service hardening discipline.";
} else {
  executiveSummary = "Informational findings detected. Review exposed services and maintain baseline hardening.";
}

// ---------------- label for display ----------------
const riskIndexLabel = `${threatLevel}-${securityScore.toFixed(1)}`;

return [
  {
    json: {
      ...d,
      risk_index: riskIndex,
      risk_index_label: riskIndexLabel,
      security_score: securityScore,
      security_grade: securityGrade,
      threat_level: threatLevel,
      security_status: securityStatus,
      overall_risk_posture: overallRiskPosture,
      executive_summary: executiveSummary
    }
  }
];

// CODE | Prepare Report Data
// Run Once for All Items

// ---------------- helpers ----------------
function pad2(n) { return String(n).padStart(2, "0"); }

function safeArr(v) { return Array.isArray(v) ? v : []; }

function toNumber(v, def = 0) {
  const n = Number(v);
  return Number.isFinite(n) ? n : def;
}

function upper(s) {
  return String(s ?? "").toUpperCase();
}

function uniq(arr) {
  return [...new Set(safeArr(arr).filter(Boolean))];
}

function shortText(s, max = 120) {
  const t = String(s ?? "");
  return t.length > max ? `${t.slice(0, max)}...` : t;
}

function displayLevel(r) {
  return upper(
    r.threat_level ||
    r.rule_risk ||
    r.risk_level ||
    r.severity ||
    r.cve_severity ||
    r.max_risk_level ||
    "UNKNOWN"
  );
}

function severityRank(level) {
  const L = upper(level);
  if (L === "CRITICAL" || L === "SEVERE") return 4;
  if (L === "HIGH") return 3;
  if (L === "MEDIUM" || L === "MODERATE") return 2;
  if (L === "LOW") return 1;
  if (L === "INFO") return 0;
  return 0;
}

function riskColor(level) {
  const L = upper(level);
  if (L === "CRITICAL" || L === "SEVERE") return { bg: "#FFE5E5", bd: "#FF5A5A", fg: "#7D0000", soft: "#FFF5F5" };
  if (L === "HIGH") return { bg: "#FFF1E6", bd: "#FF8A3D", fg: "#7A2F00", soft: "#FFF8F2" };
  if (L === "MEDIUM" || L === "MODERATE") return { bg: "#FFF7DB", bd: "#FFCC42", fg: "#6A4B00", soft: "#FFFDF4" };
  if (L === "LOW") return { bg: "#E9FFF0", bd: "#4CC26A", fg: "#0B5A1A", soft: "#F5FFF8" };
  if (L === "INFO") return { bg: "#F2F4F7", bd: "#D0D5DD", fg: "#344054", soft: "#FAFBFC" };
  return { bg: "#F2F4F7", bd: "#D0D5DD", fg: "#344054", soft: "#FAFBFC" };
}

function buildServiceLabel(r) {
  const serviceName = String(r.service_name || "").trim();
  const service = String(r.service || "").trim();
  const product = String(r.product || "").trim();
  return serviceName || service || product || "-";
}

function buildCveLabel(r) {
  const top = String(r.top_cve_id || "").trim();
  if (top) return top;

  const raw = String(r.cve_ids || r.cve || "").trim();
  if (!raw) return "-";

  const first = raw.split(",").map(x => x.trim()).filter(Boolean)[0];
  return first || "-";
}

function formatHostTopFinding(arr) {
  const a = safeArr(arr);
  if (!a.length) return "-";

  const top = a
    .slice()
    .sort((x, y) => {
      const sr = severityRank(displayLevel(y)) - severityRank(displayLevel(x));
      if (sr !== 0) return sr;
      return toNumber(y.security_score, toNumber(y.risk_score, 0)) - toNumber(x.security_score, toNumber(x.risk_score, 0));
    })[0];

  const svc = buildServiceLabel(top);
  const port = top.port ?? "-";
  const risk = displayLevel(top);
  const cve = buildCveLabel(top);
  return `${svc}:${port} (${risk}${cve !== "-" ? ` | ${cve}` : ""})`;
}

function avg(arr) {
  const a = safeArr(arr).map(x => Number(x)).filter(x => Number.isFinite(x));
  if (!a.length) return 0;
  return a.reduce((s, n) => s + n, 0) / a.length;
}

function getOverallThreat(counts) {
  if ((counts.CRITICAL || 0) > 0) return "CRITICAL";
  if ((counts.HIGH || 0) > 0) return "HIGH";
  if ((counts.MEDIUM || 0) > 0) return "MEDIUM";
  if ((counts.LOW || 0) > 0) return "LOW";
  if ((counts.INFO || 0) > 0) return "INFO";
  return "UNKNOWN";
}

// ---------------- time ----------------
const now = new Date(Date.now() + 7 * 60 * 60 * 1000);
const yyyy = now.getUTCFullYear();
const mm = pad2(now.getUTCMonth() + 1);
const dd = pad2(now.getUTCDate());
const hh = pad2(now.getUTCHours());
const mi = pad2(now.getUTCMinutes());
const ss = pad2(now.getUTCSeconds());

const scanTimeTH = `${dd}/${mm}/${yyyy + 543} ${hh}:${mi}:${ss}`;
const scannedAtISO = `${yyyy}-${mm}-${dd}T${hh}:${mi}:${ss}+07:00`;
const reportName = `SmartInfra_L5_Security_Intelligence_${yyyy}-${mm}-${dd}_${hh}${mi}${ss}`;

// ---------------- binary source from merge ----------------
const firstBinaryItem = items.find(i => i.binary && typeof i.binary === "object") || null;
const bin0 = firstBinaryItem?.binary || {};

// ---------------- source data from previous nodes ----------------
const findings = $('CODE | Filter Latest Scan').all().map(i => {
  const r = i.json || {};
  return {
    ...r,
    ip: String(r.ip || r.host || "-").trim() || "-"
  };
});

const metrics = $('CODE | Build Security Metrics').first().json || {};
const scoreData = $('CODE | Calculate Security Score').first().json || {};

// ---------------- summary values ----------------
const l5SecurityScore = toNumber(scoreData.security_score, 0);
const l5SecurityGrade = String(scoreData.security_grade || "N/A");
const l5RiskIndex = toNumber(scoreData.risk_index, 0);
const l5SecurityStatus = String(scoreData.security_status || "UNKNOWN");

// ---------------- totals ----------------
const totalFindings = findings.length;
const uniqueHosts = uniq(findings.map(r => String(r.ip || "").trim()).filter(Boolean));
const totalHosts = uniqueHosts.length;

// ---------------- counts from REAL findings ----------------
const counts = { CRITICAL: 0, HIGH: 0, MEDIUM: 0, LOW: 0, INFO: 0, UNKNOWN: 0 };

let totalRiskScore = 0;
let totalSecurityScore = 0;
let securityScoreCount = 0;
let kevCount = 0;
let cveDetectedCount = 0;

for (const r of findings) {
  const lvl = displayLevel(r);
  if (counts[lvl] !== undefined) counts[lvl] += 1;
  else counts.UNKNOWN += 1;

  totalRiskScore += toNumber(r.risk_score, 0);

  const ssNum = toNumber(r.security_score, NaN);
  if (Number.isFinite(ssNum)) {
    totalSecurityScore += ssNum;
    securityScoreCount += 1;
  }

  if (r.kev_exploited || r.kev || r.is_kev || r.known_exploited || r.cisa_kev) kevCount += 1;
  if (r.cve_found || r.cve || r.cve_ids || r.top_cve_id) cveDetectedCount += 1;
}

const avgRiskScore =
  metrics.avg_risk_score !== undefined
    ? toNumber(metrics.avg_risk_score, 0)
    : (totalFindings ? totalRiskScore / totalFindings : 0);

const avgSecurityScore = securityScoreCount ? (totalSecurityScore / securityScoreCount) : l5SecurityScore;

// ---------------- threat / posture from REAL findings ----------------
const overallThreat = getOverallThreat(counts);
const overallThreatColor = riskColor(overallThreat);
const l5ThreatLevel = overallThreat;
const l5OverallRiskPosture = overallThreat;

// ---------------- grade from report score ----------------
let overallSecurityGrade = "F";
if (l5SecurityScore >= 90) overallSecurityGrade = "A";
else if (l5SecurityScore >= 80) overallSecurityGrade = "B";
else if (l5SecurityScore >= 70) overallSecurityGrade = "C";
else if (l5SecurityScore >= 60) overallSecurityGrade = "D";

let postureText = "System posture appears stable with low immediate exposure.";
if (overallThreat === "CRITICAL") postureText = "Immediate action required. Critical-risk findings detected in the current attack surface.";
else if (overallThreat === "HIGH") postureText = "Elevated risk posture. High-risk exposures should be prioritized for remediation.";
else if (overallThreat === "MEDIUM") postureText = "Moderate exposure detected. Corrective controls and hardening are recommended.";
else if (overallThreat === "LOW") postureText = "Low-risk exposures detected. Maintain patching and service hardening discipline.";
else if (overallThreat === "INFO") postureText = "Informational findings detected. Review exposed services and maintain baseline hardening.";
else postureText = "No significant findings were detected in the current dataset.";

// ---------------- group by host ----------------
const hostMap = new Map();

for (const r of findings) {
  const ip = String(r.ip || "-").trim() || "-";

  if (!hostMap.has(ip)) {
    hostMap.set(ip, {
      ip,
      findings: [],
      ports: new Set(),
      max_risk_level: "INFO",
      max_risk_score: 0,
      max_security_score: 0,
      critical_count: 0,
      high_count: 0,
      medium_count: 0,
      low_count: 0,
      info_count: 0,
      kev_count: 0,
      cve_count: 0
    });
  }

  const h = hostMap.get(ip);
  h.findings.push(r);

  if (r.port !== undefined && r.port !== null && String(r.port) !== "") {
    h.ports.add(String(r.port));
  }

  const lvl = displayLevel(r);
  if (lvl === "CRITICAL") h.critical_count += 1;
  else if (lvl === "HIGH") h.high_count += 1;
  else if (lvl === "MEDIUM") h.medium_count += 1;
  else if (lvl === "LOW") h.low_count += 1;
  else h.info_count += 1;

  if (r.kev_exploited || r.kev || r.is_kev || r.known_exploited || r.cisa_kev) h.kev_count += 1;
  if (r.cve_found || r.cve || r.cve_ids || r.top_cve_id) h.cve_count += 1;

  const rs = toNumber(r.risk_score, 0);
  const ssNum = toNumber(r.security_score, l5SecurityScore);

  if (
    severityRank(lvl) > severityRank(h.max_risk_level) ||
    (severityRank(lvl) === severityRank(h.max_risk_level) && ssNum > h.max_security_score)
  ) {
    h.max_risk_level = lvl;
    h.max_risk_score = rs;
    h.max_security_score = ssNum;
  }
}

const hosts = [...hostMap.values()];

// ---------------- top hosts ----------------
const top5Hosts = hosts
  .map(h => ({
    ...h,
    ports_display: [...h.ports].sort((a, b) => Number(a) - Number(b)).join(", "),
    finding_count: h.findings.length,
    top_finding: formatHostTopFinding(h.findings),
    avg_security_score: avg(h.findings.map(x => toNumber(x.security_score, l5SecurityScore)))
  }))
  .sort((a, b) => {
    const sr = severityRank(b.max_risk_level) - severityRank(a.max_risk_level);
    if (sr !== 0) return sr;
    return b.max_security_score - a.max_security_score;
  })
  .slice(0, 5);

// ---------------- top findings ----------------
const top10Findings = findings
  .slice()
  .sort((a, b) => {
    const sr = severityRank(displayLevel(b)) - severityRank(displayLevel(a));
    if (sr !== 0) return sr;
    return toNumber(b.security_score, toNumber(b.risk_score, 0)) - toNumber(a.security_score, toNumber(a.risk_score, 0));
  })
  .slice(0, 10);

// ---------------- executive lists ----------------
const executiveTop3Findings = top10Findings.slice(0, 3).map(r => ({
  ip: r.ip || "-",
  service_label: buildServiceLabel(r),
  port: r.port ?? "-",
  threat: displayLevel(r),
  finding: shortText(r.finding || "-", 100),
  cve: buildCveLabel(r)
}));

const executiveTop3Hosts = top5Hosts.slice(0, 3).map(h => ({
  ip: h.ip,
  threat: h.max_risk_level,
  findings: h.finding_count,
  kev_count: h.kev_count,
  ports: h.ports_display || "-"
}));

// ---------------- output ----------------
return [{
  json: {
    report_name: reportName,
    scanned_at: scannedAtISO,
    scan_time_th: scanTimeTH,

    total_hosts: totalHosts,
    total_findings: totalFindings,
    affected_hosts: totalHosts,

    avg_risk_score: Number(avgRiskScore.toFixed(1)),
    avg_security_score: Number(avgSecurityScore.toFixed(1)),
    security_score: Number(l5SecurityScore.toFixed(1)),
    security_grade: l5SecurityGrade,

    risk_index: l5RiskIndex,
    threat_level: l5ThreatLevel,
    security_status: l5SecurityStatus,
    overall_risk_posture: l5OverallRiskPosture,

    overall_threat: overallThreat,
    overall_threat_color: overallThreatColor,
    overall_security_grade: overallSecurityGrade,
    posture_text: postureText,

    critical_count: counts.CRITICAL,
    high_count: counts.HIGH,
    medium_count: counts.MEDIUM,
    low_count: counts.LOW,
    info_count: counts.INFO,
    unknown_count: counts.UNKNOWN,

    cve_count: cveDetectedCount,
    kev_count: kevCount,
    risk_distribution: counts,

    executive_top_3_findings: executiveTop3Findings,
    executive_top_3_hosts: executiveTop3Hosts,

    top5_hosts: top5Hosts,
    top10_findings: top10Findings,
    findings,

    _debug_findings_from_filter_latest_scan: findings.length,
    _debug_metrics_found: Object.keys(metrics).length > 0,
    _debug_score_found: Object.keys(scoreData).length > 0,
    _debug_binary_keys: Object.keys(bin0 || {})
