    .replaceAll('"', "&quot;")
    .replaceAll("'", "&#39;");
}

// ---------------- binary -> data uri ----------------
async function binaryToBase64(prop, fallbackMime = "image/png") {
  const binaryIndex = items.findIndex(i => i.binary && i.binary[prop]);
  if (binaryIndex === -1) return { base64: "", mime: fallbackMime, via: "none" };

  const b = items[binaryIndex].binary[prop];
  const mime = b?.mimeType || fallbackMime;

  try {
    const buffer = await this.helpers.getBinaryDataBuffer(binaryIndex, prop);
    if (!buffer) return { base64: "", mime, via: "no_buffer" };
    return { base64: buffer.toString("base64"), mime, via: "helper" };
  } catch (e) {
    const direct = b?.data || "";
    if (direct && typeof direct === "string" && direct.length > 1000) {
      return { base64: direct, mime, via: "direct" };
    }
    return { base64: "", mime, via: "error" };
  }
}

