// ---------------- top CVE rows ----------------
const topCveRows = findings
  .filter(r =>
    r.cve_found || r.cve || r.cve_ids || r.top_cve_id ||
    r.kev_exploited || r.kev || r.is_kev || r.known_exploited || r.cisa_kev
  )
  .slice()
  .sort((a, b) => {
    const bKev = Boolean(b.kev_exploited || b.kev || b.is_kev || b.known_exploited || b.cisa_kev);
    const aKev = Boolean(a.kev_exploited || a.kev || a.is_kev || a.known_exploited || a.cisa_kev);
    if (bKev !== aKev) return Number(bKev) - Number(aKev);

    const sr =
      severityRank(b.threat_level || b.rule_risk || b.risk_level || b.severity || b.cve_severity || "UNKNOWN") -
      severityRank(a.threat_level || a.rule_risk || a.risk_level || a.severity || a.cve_severity || "UNKNOWN");
    if (sr !== 0) return sr;

    return toNumber(b.max_cvss_score, 0) - toNumber(a.max_cvss_score, 0);
  })
  .slice(0, 10)
  .map(r => `
    <tr>
      <td class="cell-host">${esc(r.ip || "-")}</td>
      <td class="cell-center mono">${esc(r.port ?? "-")}</td>
      <td class="cell-left">${esc(buildServiceLabel(r))}</td>
      <td class="cell-left small mono">${esc(buildCveLabel(r))}</td>
      <td class="cell-center mono">${esc(toNumber(r.max_cvss_score, 0).toFixed(1))}</td>
      <td class="cell-center">${(r.kev_exploited || r.kev || r.is_kev || r.known_exploited || r.cisa_kev) ? `<span class="badge badge-critical">KEV</span>` : "-"}</td>
      <td class="cell-left small">${esc(shortText(r.top_cve_description || r.finding || "-", 130))}</td>
    </tr>
  `)
  .join("");

// ---------------- remediation rows ----------------
let remediationRows = "";

for (const h of top5Hosts) {
