  const recs = uniq(hostFindings.map(x => String(x.recommendation || "").trim()).filter(Boolean));

  const issues = hostFindings
    .slice()
    .sort((a, b) => {
      const sr =
        severityRank(b.threat_level || b.rule_risk || b.risk_level || b.severity || b.cve_severity || "UNKNOWN") -
        severityRank(a.threat_level || a.rule_risk || a.risk_level || a.severity || a.cve_severity || "UNKNOWN");
      if (sr !== 0) return sr;
      return toNumber(b.security_score, toNumber(b.risk_score, 0)) - toNumber(a.security_score, toNumber(a.risk_score, 0));
    })
    .slice(0, 5)
    .map(x => {
      const svc = buildServiceLabel(x);
      const cve = buildCveLabel(x);
