    })
    .join("");

  const acts = recs.length
    ? recs.slice(0, 5).map(x => `<li>${esc(x)}</li>`).join("")
    : `<li>อัปเดตแพตช์, จำกัดการเข้าถึง, ตรวจสอบ hardening, logging และ access control ของบริการที่เปิดใช้งาน</li>`;

  remediationRows += `
